{

    int n;

    cin>>n;

    for(int i = 1;i <= n;i++)

        scanf("%d",&a[i]);

    int num = 0;

    for(int i = 1;i <= n-1;i++)

        for(int j = i+1;j <= n;j++)

            b[num++] = a[i]*a[j];



    sort(b,b+num);

    int nu = unique(b,b+num)-b;

    for(int i = nu-1;i >= 0;i--)

